+fn maybe_pause_lexical_publish_for_kill_relaunch(
+    index_path: &Path,
+    canonical_sidecar: &Path,
+) -> Result<()> {
+    let sentinel_path =
+        match dotenvy::var("CASS_TEST_LEXICAL_PUBLISH_KILL_RELAUNCH_SENTINEL") {
+            Ok(raw) if !raw.trim().is_empty() => PathBuf::from(raw),
+            _ => return Ok(()),
+        };
